import React from 'react'; // Importa a biblioteca React para criar componentes.
import './pessoa.css'; // Importa o arquivo CSS para estilizar o componente.

const Pessoa = () => { // Define o componente funcional 'Pessoa'.
    const pessoas = [ // Declara um array de objetos contendo informações sobre pessoas.
        { nome: 'ACAI DO CERRADO LTDA', cpfCnpj: '16.578.497/0001-60', telefone: 'Não informado', email: 'nao_informado@gmail.com', cidade: 'Gama - DF', uf: 'DF', tipo: 'Jurídica', status: 'Parte contrária' }, // Primeiro objeto no array com detalhes de uma pessoa jurídica.
        { nome: 'ACAI DO PRETO DISTRIBUICAO LTDA', cpfCnpj: '44.053.542/0001-06', telefone: 'Não informado', email: 'distribuicao@acai.com', cidade: 'Não informado', uf: 'GO', tipo: 'Jurídica', status: 'Cliente inativo' }, // Segundo objeto no array com detalhes de outra pessoa jurídica.
        { nome: 'ADALTO DE OLIVEIRA JUNIOR', cpfCnpj: '037.674.565-75', telefone: 'Não informado', email: 'adalto@gmail.com', cidade: 'Não informado', uf: 'SP', tipo: 'Física', status: 'Cliente' }, // Terceiro objeto no array com detalhes de uma pessoa física.
    ];

    return ( // Início do retorno do JSX do componente.
        <div className="pessoa-container"> {/* Cria uma div que serve como contêiner principal para o componente. */}
            <h1>Pessoa</h1> {/* Título principal do componente. */}
            <div className="header"> {/* Cria uma div para o cabeçalho da seção. */}
                <button className="btn-nova-pessoa">Nova pessoa</button> {/* Botão para adicionar uma nova pessoa. */}
                <input // Campo de entrada para pesquisa.
                    type="text" // Define o tipo de entrada como texto.
                    placeholder="Pesquise por nome/razão social, e-mail ou CPF/CNPJ" // Texto que aparece quando o campo está vazio.
                    className="search-bar" // Classe CSS para estilização do campo.
                />
                <button className="btn-busca-avancada">Busca avançada</button> {/* Botão para realizar uma busca avançada. */}
                <button className="btn-relatorio-simplificado">Gerar Relatório Simplificado</button> {/* Botão para gerar um relatório simplificado. */}
                <label> {/* Rótulo para o primeiro botão de opção. */}
                    <input type="radio" name="tipo-pessoa" value="todos" defaultChecked /> Todos {/* Botão de opção para selecionar todas as pessoas, com a seleção padrão. */}
                </label>
                <label> {/* Rótulo para o segundo botão de opção. */}
                    <input type="radio" name="tipo-pessoa" value="fisica" /> Pessoa Física {/* Botão de opção para selecionar apenas pessoas físicas. */}
                </label>
                <label> {/* Rótulo para o terceiro botão de opção. */}
                    <input type="radio" name="tipo-pessoa" value="juridica" /> Pessoa Jurídica {/* Botão de opção para selecionar apenas pessoas jurídicas. */}
                </label>
            </div>

            <table className="pessoa-tabela"> {/* Cria uma tabela para exibir as informações das pessoas. */}
                <thead> {/* Cabeçalho da tabela. */}
                    <tr> {/* Linha do cabeçalho. */}
                        <th>Nome</th> {/* Coluna para o nome da pessoa. */}
                        <th>CPF/CNPJ</th> {/* Coluna para o CPF ou CNPJ da pessoa. */}
                        <th>Telefone</th> {/* Coluna para o telefone da pessoa. */}
                        <th>E-mail</th> {/* Coluna para o e-mail da pessoa. */}
                        <th>Cidade</th> {/* Coluna para a cidade da pessoa. */}
                        <th>UF</th> {/* Coluna para a Unidade Federativa (Estado) da pessoa. */}
                        <th>Tipo</th> {/* Coluna para o tipo de pessoa (Física ou Jurídica). */}
                        <th>Status</th> {/* Coluna para o status da pessoa. */}
                        <th>Ações</th> {/* Coluna para ações (editar e excluir). */}
                    </tr>
                </thead>
                <tbody> {/* Corpo da tabela onde as linhas de dados serão exibidas. */}
                    {pessoas.map((pessoa, index) => ( // Mapeia o array de pessoas e gera uma linha para cada pessoa.
                        <tr key={index}> {/* Linha da tabela para cada pessoa, usando o índice como chave. */}
                            <td>{pessoa.nome}</td> {/* Célula com o nome da pessoa. */}
                            <td>{pessoa.cpfCnpj}</td> {/* Célula com o CPF ou CNPJ da pessoa. */}
                            <td>{pessoa.telefone}</td> {/* Célula com o telefone da pessoa. */}
                            <td>{pessoa.email}</td> {/* Célula com o e-mail da pessoa. */}
                            <td>{pessoa.cidade}</td> {/* Célula com a cidade da pessoa. */}
                            <td>{pessoa.uf}</td> {/* Célula com a UF da pessoa. */}
                            <td> {/* Célula para exibir o tipo da pessoa com um badge. */}
                                <span className={`status-badge ${pessoa.tipo === 'Jurídica' ? 'juridica' : 'fisica'}`}> {/* Span que mostra o tipo de pessoa, aplicando a classe correspondente. */}
                                    {pessoa.tipo} {/* Exibe o tipo de pessoa (Física ou Jurídica). */}
                                </span>
                            </td>
                            <td className="status-info">{pessoa.status}</td> {/* Célula com o status da pessoa. */}
                            <td> {/* Célula para as ações de edição e exclusão. */}
                                <button className="btn-editar">Editar</button> {/* Botão para editar a pessoa. */}
                                <button className="btn-excluir">Excluir</button> {/* Botão para excluir a pessoa. */}
                            </td>
                        </tr>
                    ))} {/* Fecha o mapeamento das pessoas. */}
                </tbody>
            </table> {/* Fecha a tabela. */}
        </div> // Fecha o contêiner principal.
    );
}; // Fecha a definição do componente.

export default Pessoa; // Exporta o componente 'Pessoa' para uso em outros arquivos.
